3_real_world_example.code:
const user = { name: 'Alice' };

// user only has one property: 'name'. 
// But we can call .toString() on it!
console.log(user.toString()); // '[object Object]'

// How? 'toString' lives on user's prototype (Object.prototype).
// The engine couldn't find 'toString' on user, so it asked the prototype.

6_edge_case.code:
const normalObj = {};
console.log(normalObj.toString); // function...

// Create an object with a NULL prototype
const pureDict = Object.create(null);
console.log(pureDict.toString); // undefined! Completely empty.
